2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	const sortCells = (cells: [number, number][]) =>
6	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
7	
8	describe("Conway's Game of Life - Next Generation", () => {
9	  it("should return an empty grid when given an empty grid", () => {
10	    expect(nextGeneration([])).toEqual([]);
11	  });
12	  it("should kill a single live cell with 0 neighbors (underpopulation)", () => {
13	    expect(nextGeneration([[0, 0]])).toEqual([]);
14	  });
15	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
16	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
17	  });
18	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
20	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
21	  });
22	  it("should keep a block still life unchanged (each cell has 3 neighbors, survives)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
24	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
25	  });
26	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
27	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
28	    expect(sortCells(result)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
29	  });
30	  it("should kill the center of a full 3x3 block due to overpopulation while corners survive", () => {
31	    // Gen 0: full 3x3 block of 9 live cells
32	    // Center (1,1) has 8 neighbors -> dies (overpopulation)
33	    // Edge cells (1,0),(0,1),(2,1),(1,2) have 5 neighbors -> die
34	    // Corner cells (0,0),(2,0),(0,2),(2,2) have 3 neighbors -> survive
35	    // Dead cells around: (1,-1),(-1,1),(3,1),(1,3) each have 3 live neighbors -> reproduce
36	    const result = nextGeneration([
37	      [0, 0], [1, 0], [2, 0],
38	      [0, 1], [1, 1], [2, 1],
39	      [0, 2], [1, 2], [2, 2],
40	    ]);
41	    expect(sortCells(result)).toEqual(
42	      sortCells([
43	        [0, 0], [2, 0], [0, 2], [2, 2],
44	        [1, -1], [-1, 1], [3, 1], [1, 3],
45	      ]),
46	    );
47	  });
48	  it("should handle negative coordinates correctly", () => {
49	    // Vertical blinker at negative coordinates should oscillate to horizontal blinker
50	    const result = nextGeneration([[-5, -5], [-5, -4], [-5, -3]]);
51	    expect(sortCells(result)).toEqual(sortCells([[-6, -4], [-5, -4], [-4, -4]]));
52	  });
53	});
