export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(encodeCell));
  const candidatesByKey = new Map<string, Cell>();
  for (const cell of liveCells) {
    candidatesByKey.set(encodeCell(cell), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidatesByKey.set(encodeCell(neighbor), neighbor);
    }
  }
  const result: Cell[] = [];
  for (const [key, cell] of candidatesByKey) {
    const liveNeighborCount = neighborsOf(cell).filter((n) =>
      liveSet.has(encodeCell(n))
    ).length;
    if (survives(liveSet.has(key), liveNeighborCount)) {
      result.push(cell);
    }
  }
  return result;
}

